import {
  AnalysisWorkerWrapper, Paper, languageProcessing, interpreters, helpers
} from "yoastseo";

class Route66Yoast {

  constructor(options = {}) {

    const defaults = {
      worker: 'https://localhost:9999/worker.js',
      locale: 'en_GB',
    };

    this.options = Object.assign({}, defaults, options || {});
    this.createWorker();
  }

  createWorker() {

    const languages = ['ar', 'ca', 'cs', 'de', 'el', 'en', 'es', 'fa', 'fr', 'he', 'hu', 'id', 'it', 'ja', 'nb', 'nl', 'pl', 'pt', 'ru', 'sk', 'sv', 'tr'];

    let language = languageProcessing.getLanguage(this.options.locale);

    if (language && languages.indexOf(language) === -1) {
      language = '_default';
    }

    const workerUnwrapped = new Worker(new URL(this.options.worker, import.meta.url));
    workerUnwrapped.postMessage({ language });
    this.worker = new AnalysisWorkerWrapper(workerUnwrapped);

    const options = {
      contentAnalysisActive: true,
      keywordAnalysisActive: true,
      inclusiveLanguageAnalysisActive: false,
      useCornerstone: false,
      useTaxonomy: false,
      locale: this.options.locale,
      logLevel: 'ERROR',
    };

    if (this.options.i18n) {
      options.translations = this.options.i18n;
    }

    this.worker.initialize(options).then(() => {
      console.info('Route 66 analyzer worker initialized');
    }).catch((error) => {
      console.error('Route 66 analyzer worker failed:');
      console.error(error);
    });
  }

  analyze(text = '', attributes = {}) {

    attributes.titleWidth = helpers.measureTextWidth(attributes.title);

    // This removes some HTML tags
    text = languageProcessing.helpers.removeHtmlBlocks(text);

    this.paper = new Paper(text, attributes);
    return this.worker.analyze(this.paper);
  }

  getRatingFromScore(score) {
    return interpreters.scoreToRating(score);
  }


}

export default Route66Yoast;